function syncDropdownHeight() {
  if (window.innerWidth < 1201) return;

  const dropdown = document.querySelector('.header-menu-catalog__dropdown');
  const menu1 = document.querySelector('.header-menu-catalog__menu1');

  if (!dropdown || !menu1) return;

  const menus2 = document.querySelectorAll('.header-menu-catalog__menu2');
  const menus3 = document.querySelectorAll('.header-menu-catalog__menu3');
  const originalStyles = [];

  menus2.forEach(menu => {
    originalStyles.push({
      menu: menu,
      opacity: menu.style.opacity,
      pointerEvents: menu.style.pointerEvents,
      display: menu.style.display
    });
    menu.style.opacity = '1';
    menu.style.pointerEvents = 'auto';
    menu.style.display = 'flex';
  });

  menus3.forEach(menu => {
    originalStyles.push({
      menu: menu,
      opacity: menu.style.opacity,
      pointerEvents: menu.style.pointerEvents,
      display: menu.style.display
    });
    menu.style.opacity = '1';
    menu.style.pointerEvents = 'auto';
    menu.style.display = 'flex';
  });

  let maxHeight = menu1.scrollHeight;

  menus2.forEach(menu => {
    const height = menu.scrollHeight;
    if (height > maxHeight) maxHeight = height;
  });

  menus3.forEach(menu => {
    const height = menu.scrollHeight;
    if (height > maxHeight) maxHeight = height;
  });

  originalStyles.forEach(original => {
    original.menu.style.opacity = original.opacity;
    original.menu.style.pointerEvents = original.pointerEvents;
    original.menu.style.display = original.display;
  });

  dropdown.style.height = maxHeight + 'px';

  menu1.style.height = maxHeight + 'px';
  menus2.forEach(menu => {
    menu.style.height = maxHeight + 'px';
  });
  menus3.forEach(menu => {
    menu.style.height = maxHeight + 'px';
  });
}

document.querySelectorAll('.header-menu-catalog__item1').forEach(item => {
  item.addEventListener('mouseenter', () => {
    setTimeout(syncDropdownHeight, 10);
  });
});

document.querySelectorAll('.header-menu-catalog__item2').forEach(item => {
  item.addEventListener('mouseenter', () => {
    setTimeout(syncDropdownHeight, 10);
  });
});

document.addEventListener('DOMContentLoaded', syncDropdownHeight);

